import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Modules and Imports","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/modules.md","filePath":"archive/reference/modules.md"}'),o={name:"archive/reference/modules.md"};function i(p,e,l,r,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="modules-and-imports" tabindex="-1">Modules and Imports <a class="header-anchor" href="#modules-and-imports" aria-label="Permalink to &quot;Modules and Imports&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>Vex uses a file-based module system with explicit exports, inspired by JavaScript/TypeScript but with static resolution.</p><hr><h2 id="_1-module-basics" tabindex="-1">1. Module Basics <a class="header-anchor" href="#_1-module-basics" aria-label="Permalink to &quot;1. Module Basics&quot;">​</a></h2><p>Each file is a module. By default, all symbols are <strong>private</strong> unless exported.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// math.vx</span></span>
<span class="line"><span>fn helper(x: i32): i32 { return x * 2; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export fn double_add(x: i32, y: i32): i32 {</span></span>
<span class="line"><span>    return helper(x) + helper(y);</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_2-imports" tabindex="-1">2. Imports <a class="header-anchor" href="#_2-imports" aria-label="Permalink to &quot;2. Imports&quot;">​</a></h2><p>Imports are resolved at compile-time. Circular imports are allowed but discouraged (handled via multi-pass resolution).</p><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Named imports (Recommended)</span></span>
<span class="line"><span>import { println, readln } from &quot;io&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Namespace import</span></span>
<span class="line"><span>import * as io from &quot;io&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Nested module import</span></span>
<span class="line"><span>import { TcpStream } from &quot;net/tcp&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Relative import (Same package)</span></span>
<span class="line"><span>import { Helper } from &quot;./utils.vx&quot;;</span></span></code></pre></div><h3 id="resolution-rules" tabindex="-1">Resolution Rules <a class="header-anchor" href="#resolution-rules" aria-label="Permalink to &quot;Resolution Rules&quot;">​</a></h3><ol><li><strong>Standard Library</strong>: <code>import ... from &quot;io&quot;</code> looks in <code>std/io</code>.</li><li><strong>Package</strong>: <code>import ... from &quot;pkg&quot;</code> looks in <code>vex.json</code> dependencies.</li><li><strong>Local</strong>: <code>import ... from &quot;./foo&quot;</code> looks in current directory.</li></ol><hr><h2 id="_3-exports" tabindex="-1">3. Exports <a class="header-anchor" href="#_3-exports" aria-label="Permalink to &quot;3. Exports&quot;">​</a></h2><p>Vex is explicit about visibility.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export fn public_api() {}</span></span>
<span class="line"><span>export struct User { ... }</span></span>
<span class="line"><span>export const MAX_RETRIES = 3;</span></span>
<span class="line"><span>export contract Runnable { ... }</span></span></code></pre></div><h3 id="re-exports" tabindex="-1">Re-exports <a class="header-anchor" href="#re-exports" aria-label="Permalink to &quot;Re-exports&quot;">​</a></h3><p>Re-export symbols from other modules:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export { TcpStream } from &quot;net/tcp&quot;;</span></span></code></pre></div><hr><h2 id="_4-internal-visibility" tabindex="-1">4. Internal Visibility <a class="header-anchor" href="#_4-internal-visibility" aria-label="Permalink to &quot;4. Internal Visibility&quot;">​</a></h2><p>Vex packages can have <code>internal</code> visibility (accessible within package but not outside), but this is currently implicitly handled by simply <em>not</em> exporting from the root <code>lib.vx</code>.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Unlike Rust <code>pub(crate)</code>, Vex generally relies on <code>export</code> at the file level + <code>vex.json</code> to define the public API surface.</p></div><hr><h2 id="_5-module-context" tabindex="-1">5. Module Context <a class="header-anchor" href="#_5-module-context" aria-label="Permalink to &quot;5. Module Context&quot;">​</a></h2><p>When you import a function, it retains access to its original module&#39;s private internals only. It does <em>not</em> gain access to the importer&#39;s privates.</p>`,28)])])}const m=a(o,[["render",i]]);export{h as __pageData,m as default};
